const headers = $input.item.json.headers || {};
const body    = $input.item.json.body || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
const token   = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };

const intent         = String(body.intent || '').trim();
const target_avatar  = body.target_avatar ? String(body.target_avatar).trim().toUpperCase() : '';
const vertical_hint  = body.vertical_hint ? String(body.vertical_hint).trim() : '';
const lead_id        = body.lead_id || null;

if (!intent) return { json: { _unauthorized: true, status: 400, error: 'intent is required' } };

return { json: { token, intent, target_avatar, vertical_hint, lead_id } };

const rows = $input.item.json;
const row  = Array.isArray(rows) ? rows[0] : (rows && rows.id ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };

// Carry forward routing inputs alongside the resolved user.
const prior = $('Extract').item.json;
return { json: {
  _ok: true,
  user_id:        row.user_id,
  user_role:      row.user_role,
  intent:         prior.intent,
  target_avatar:  prior.target_avatar,
  vertical_hint:  prior.vertical_hint,
  lead_id:        prior.lead_id
} };

// Build the PostgREST query string for avatars.
// Priority:
//   1. target_avatar → eq.<name> (case-insensitive uppercase)
//   2. vertical_hint → eq.<vertical>, AND active=eq.true (only live rows in vertical-match path)
//   3. neither       → null filter; caller falls back to its own vertical default
//
// Schedule-window matching happens client-side after the query — keeps
// the SQL simple and lets us iterate the matching rule without a migration.

const d = $input.item.json;
let filter = '';
let path   = '';

if (d.target_avatar) {
  filter = `avatar_name=eq.${encodeURIComponent(d.target_avatar)}`;
  path = 'target_avatar';
} else if (d.vertical_hint) {
  filter = `business_vertical=eq.${encodeURIComponent(d.vertical_hint)}&active=eq.true`;
  path = 'vertical_match';
} else {
  path = 'no_filter_fallback';
}

return { json: {
  ...d,
  _filter: filter,
  _path:   path,
  _should_query: filter ? true : false
} };

// Apply schedule-window matching + pick exactly one row.
//
// Output contract — caller always gets a stable shape:
//   { avatar_id: null|uuid, avatar: null|{...row}, resolved_via: 'target_avatar' | 'vertical_match' | 'vertical_default_fallback' | 'no_match', schedule_matches: bool }
//
// resolved_via='vertical_default_fallback' means the caller should use
// its existing hard-coded vertical→persona lookup; we return null so
// callers can branch cleanly on `avatar_id != null`.

const prior = $('Build Query').item.json;
const raw   = $input.item.json;
// PostgREST returns an array on success; on neverError the body may be the error JSON.
const rows = Array.isArray(raw) ? raw : (raw && raw.data && Array.isArray(raw.data) ? raw.data : []);

function nowInTz(tz) {
  try { return new Date(new Date().toLocaleString('en-US', { timeZone: tz || 'America/Toronto' })); }
  catch (e) { return new Date(); }
}
function dayKey(d) { return ['sun','mon','tue','wed','thu','fri','sat'][d.getDay()]; }
function hmFromDate(d) { const h = String(d.getHours()).padStart(2,'0'); const m = String(d.getMinutes()).padStart(2,'0'); return `${h}:${m}`; }
function inWindow(row) {
  const sched = row.content_schedule || {};
  const windows = Array.isArray(sched.broadcast_windows) ? sched.broadcast_windows : [];
  if (!windows.length) return true; // no schedule = always-on
  const now = nowInTz(sched.timezone);
  const day = dayKey(now);
  const hm  = hmFromDate(now);
  for (const w of windows) {
    const days = Array.isArray(w.days) ? w.days : [];
    if (!days.includes(day)) continue;
    const s = String(w.start || '00:00');
    const e = String(w.end   || '23:59');
    if (hm >= s && hm <= e) return true;
  }
  return false;
}

let picked = null;
let schedule_matches = null;

if (rows.length === 0) {
  picked = null;
} else if (rows.length === 1) {
  picked = rows[0];
  schedule_matches = inWindow(picked);
} else {
  // Prefer rows whose schedule window contains "now". If multiple match,
  // take the one whose updated_at is oldest (round-robin freshness).
  const inWin = rows.filter(inWindow);
  const pool = inWin.length ? inWin : rows;
  pool.sort((a, b) => {
    const au = a.updated_at || a.created_at || '';
    const bu = b.updated_at || b.created_at || '';
    return au.localeCompare(bu);
  });
  picked = pool[0];
  schedule_matches = inWindow(picked);
}

let resolved_via;
if (!picked && prior._path === 'no_filter_fallback') resolved_via = 'vertical_default_fallback';
else if (!picked) resolved_via = 'no_match';
else if (prior._path === 'target_avatar') resolved_via = 'target_avatar';
else if (prior._path === 'vertical_match') resolved_via = 'vertical_match';
else resolved_via = 'vertical_default_fallback';

return { json: {
  avatar_id:        picked ? picked.id : null,
  avatar:           picked || null,
  resolved_via,
  schedule_matches: schedule_matches === null ? false : schedule_matches,
  // Context echo for the calling workflow
  intent:           prior.intent,
  vertical_hint:    prior.vertical_hint,
  target_avatar:    prior.target_avatar,
  lead_id:          prior.lead_id
} };

const d = $input.item.json;
return { json: {
  ok: true,
  data: {
    avatar_id:        d.avatar_id,
    avatar:           d.avatar,
    resolved_via:     d.resolved_via,
    schedule_matches: d.schedule_matches,
    intent:           d.intent,
    vertical_hint:    d.vertical_hint,
    target_avatar:    d.target_avatar,
    lead_id:          d.lead_id
  }
} };
